/**
 * CSV Parser Library
 * A comprehensive CSV parsing library with type coercion, error handling, and data manipulation methods
 */

interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

interface ParseError {
  row: number;
  message: string;
}

interface GroupedData {
  [key: string]: Array<Record<string, any>>;
}

class CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];

  constructor(
    rows: Array<Record<string, any>>,
    headers: string[],
    errors: ParseError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
    const filteredRows = this.rows.filter(predicate);
    return new CSVResult(filteredRows, this.headers, this.errors);
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    return this.rows.reduce((sum, row) => {
      const value = row[column];
      const numValue = typeof value === 'number' ? value : 0;
      return sum + numValue;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    if (this.rows.length === 0) {
      return 0;
    }

    const sum = this.sum(column);
    return sum / this.rows.length;
  }

  /**
   * Count total rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column: string): Map<string, Array<Record<string, any>>> {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    const grouped = new Map<string, Array<Record<string, any>>>();

    for (const row of this.rows) {
      const key = String(row[column] ?? 'null');
      if (!grouped.has(key)) {
        grouped.set(key, []);
      }
      grouped.get(key)!.push(row);
    }

    return grouped;
  }
}

/**
 * Coerce a string value to its appropriate type
 */
function coerceValue(value: string): any {
  // Handle null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Try to parse as number
  if (/^-?\d+(\.\d+)?$/.test(value)) {
    const num = parseFloat(value);
    return isNaN(num) ? value : num;
  }

  // Try to parse as boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into structured data
 */
function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors: ParseError[] = [];

  if (!input || input.trim() === '') {
    return new CSVResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  // Remove trailing empty lines
  while (lines.length > 0 && lines[lines.length - 1].trim() === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], errors);
  }

  let headers: string[] = [];
  const rows: Array<Record<string, any>> = [];

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    try {
      const fields = parseCSVLine(line, delimiter, quoteChar);

      if (lineIndex === 0) {
        // First line is headers
        headers = fields;
      } else {
        // Create object from fields
        const row: Record<string, any> = {};

        // Handle rows with fewer or more fields than headers
        for (let i = 0; i < headers.length; i++) {
          const header = headers[i];
          const field = i < fields.length ? fields[i] : '';
          row[header] = coerceValue(field);
        }

        // If there are more fields than headers, add them with generic names
        for (let i = headers.length; i < fields.length; i++) {
          const header = `field_${i}`;
          const field = fields[i];
          row[header] = coerceValue(field);
        }

        rows.push(row);
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown parsing error';
      errors.push({
        row: lineIndex + 1,
        message: errorMessage,
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

/**
 * Parse a single CSV line into fields
 * Handles quoted fields with escaped quotes
 */
function parseCSVLine(
  line: string,
  delimiter: string,
  quoteChar: string
): string[] {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quoteChar) {
      // Check if it's an escaped quote (two quotes in a row)
      if (i + 1 < line.length && line[i + 1] === quoteChar) {
        // Escaped quote
        currentField += quoteChar;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Delimiter outside quotes
      fields.push(currentField);
      currentField = '';
      i++;
    } else {
      currentField += char;
      i++;
    }
  }

  // Add the last field
  fields.push(currentField);

  // Validate that quotes are properly closed
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

export { parseCSV, CSVResult, CSVOptions, ParseError };

/**
 * CSV Parser Test Suite
 * Comprehensive tests for all CSV parsing functionality
 */

import { parseCSV, CSVResult } from './csv-parser';

// Test utilities
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertThrows(fn: () => void, message: string): void {
  try {
    fn();
    throw new Error(`Assertion failed: ${message} - Expected exception but none was thrown`);
  } catch (error) {
    if (error instanceof Error && error.message.includes('Assertion failed')) {
      throw error;
    }
    // Expected to throw
  }
}

function test(name: string, fn: () => void): void {
  try {
    fn();
    console.log(`вң“ ${name}`);
  } catch (error) {
    console.error(`вң— ${name}`);
    console.error(`  ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}

// ============================================================================
// TEST SUITE
// ============================================================================

console.log('\n=== Basic Parsing Tests ===\n');

test('should parse basic CSV with headers and one row', () => {
  const csv = 'name,age,city\nJohn,30,NYC';
  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEquals(result.rows.length, 1, 'Should have 1 row');
  assertEquals(result.rows[0], { name: 'John', age: 30, city: 'NYC' }, 'Row data should match');
});

test('should parse basic CSV with multiple rows', () => {
  const csv = 'name,age\nAlice,25\nBob,35';
  const result = parseCSV(csv);

  assertEquals(result.headers, ['name', 'age'], 'Headers should match');
  assertEquals(result.rows.length, 2, 'Should have 2 rows');
  assertEquals(result.rows[0].name, 'Alice', 'First row name should be Alice');
  assertEquals(result.rows[1].name, 'Bob', 'Second row name should be Bob');
});

test('should handle single column CSV', () => {
  const csv = 'email\ntest@example.com\nuser@example.com';
  const result = parseCSV(csv);

  assertEquals(result.headers, ['email'], 'Should have single header');
  assertEquals(result.rows.length, 2, 'Should have 2 rows');
  assertEquals(result.rows[0].email, 'test@example.com', 'First email should match');
});

test('should handle single row CSV', () => {
  const csv = 'name,value\ntest,123';
  const result = parseCSV(csv);

  assertEquals(result.rows.length, 1, 'Should have 1 row');
  assertEquals(result.rows[0].name, 'test', 'Row name should match');
});

console.log('\n=== Quoted Fields Tests ===\n');

test('should handle quoted fields with commas inside', () => {
  const csv = 'name,address\n"Smith, John","123 Main St, Apt 4"';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'Smith, John', 'Name should include comma');
  assertEquals(
    result.rows[0].address,
    '123 Main St, Apt 4',
    'Address should include comma'
  );
});

test('should handle quoted fields with line breaks', () => {
  const csv = 'name,description\n"John","Line 1\nLine 2"';
  const result = parseCSV(csv, { lineSeparator: '\n' });

  // Note: This tests that we properly split by line separator
  assertEquals(result.rows[0].name, 'John', 'Name should be John');
});

test('should handle quoted empty fields', () => {
  const csv = 'name,age,city\n"John","",""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John', 'Name should be John');
  assertEquals(result.rows[0].age, null, 'Empty age should be null');
  assertEquals(result.rows[0].city, null, 'Empty city should be null');
});

test('should handle fields with leading/trailing spaces inside quotes', () => {
  const csv = 'name,value\n" John "," 123 "';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, ' John ', 'Name should preserve spaces');
  assertEquals(result.rows[0].value, ' 123 ', 'Value should preserve spaces');
});

console.log('\n=== Escaped Quotes Tests ===\n');

test('should handle escaped quotes (double quotes)', () => {
  const csv = 'name,comment\n"John ""The Great""","Quote: ""Hello"""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John "The Great"', 'Name should have single quotes');
  assertEquals(result.rows[0].comment, 'Quote: "Hello"', 'Comment should have single quotes');
});

test('should handle multiple escaped quotes in a row', () => {
  const csv = 'text\n"""""""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, '"""', 'Should have three quotes');
});

test('should handle escaped quotes at start and end', () => {
  const csv = 'value\n"""quoted"""';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, '"quoted"', 'Should have quotes at start and end');
});

console.log('\n=== Custom Delimiters Tests ===\n');

test('should parse with semicolon delimiter', () => {
  const csv = 'name;age;city\nJohn;30;NYC';
  const result = parseCSV(csv, { delimiter: ';' });

  assertEquals(result.headers, ['name', 'age', 'city'], 'Headers should match');
  assertEquals(result.rows[0].name, 'John', 'Name should match');
  assertEquals(result.rows[0].age, 30, 'Age should match');
});

test('should parse with tab delimiter', () => {
  const csv = 'name\tage\tvalue\nJohn\t30\t100';
  const result = parseCSV(csv, { delimiter: '\t' });

  assertEquals(result.headers, ['name', 'age', 'value'], 'Headers should match');
  assertEquals(result.rows[0].age, 30, 'Age should be parsed');
});

test('should parse with pipe delimiter', () => {
  const csv = 'id|name|status\n1|Alice|active';
  const result = parseCSV(csv, { delimiter: '|' });

  assertEquals(result.headers, ['id', 'name', 'status'], 'Headers should match');
  assertEquals(result.rows[0].id, 1, 'ID should be parsed');
});

test('should parse with custom quote character', () => {
  const csv = "name,comment\nJohn,'Smith, Jr.'\nAlice,'Has, comma'";
  const result = parseCSV(csv, { quoteChar: "'" });

  assertEquals(result.rows[0].comment, 'Smith, Jr.', 'Comment with comma should be preserved');
  assertEquals(result.rows[1].comment, 'Has, comma', 'Second comment should be preserved');
});

test('should parse with custom delimiter and quote character', () => {
  const csv = "name;comment\nJohn;'Test; value'\nAlice;'Another; test'";
  const result = parseCSV(csv, { delimiter: ';', quoteChar: "'" });

  assertEquals(result.headers, ['name', 'comment'], 'Headers should match');
  assertEquals(result.rows[0].comment, 'Test; value', 'Comment should preserve delimiter');
});

console.log('\n=== Type Coercion Tests ===\n');

test('should coerce integers', () => {
  const csv = 'count,value\n42,100';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].count, 42, 'Should be integer 42');
  assertEquals(typeof result.rows[0].count, 'number', 'Should be number type');
});

test('should coerce negative integers', () => {
  const csv = 'value\n-50';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, -50, 'Should be -50');
});

test('should coerce floats', () => {
  const csv = 'price,discount\n19.99,0.15';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].price, 19.99, 'Should be float 19.99');
  assertEquals(result.rows[0].discount, 0.15, 'Should be float 0.15');
});

test('should coerce negative floats', () => {
  const csv = 'value\n-3.14';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, -3.14, 'Should be -3.14');
});

test('should coerce boolean true (lowercase)', () => {
  const csv = 'active\ntrue';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'Should be boolean true');
  assertEquals(typeof result.rows[0].active, 'boolean', 'Should be boolean type');
});

test('should coerce boolean false (lowercase)', () => {
  const csv = 'active\nfalse';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, false, 'Should be boolean false');
});

test('should coerce boolean true (uppercase)', () => {
  const csv = 'active\nTRUE';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'Should be boolean true');
});

test('should coerce boolean false (uppercase)', () => {
  const csv = 'active\nFALSE';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, false, 'Should be boolean false');
});

test('should coerce boolean true (mixed case)', () => {
  const csv = 'active\nTrUe';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, 'Should be boolean true');
});

test('should coerce empty string to null', () => {
  const csv = 'name,value\nJohn,';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, 'Empty value should be null');
});

test('should coerce "null" string to null', () => {
  const csv = 'value\nnull';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, '"null" should be null');
});

test('should coerce "NULL" string to null', () => {
  const csv = 'value\nNULL';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, '"NULL" should be null');
});

test('should keep strings as strings', () => {
  const csv = 'name,city\nJohn,NewYork';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John', 'Should be string');
  assertEquals(typeof result.rows[0].name, 'string', 'Should be string type');
});

test('should keep numeric strings with leading zeros', () => {
  const csv = 'code\n00123';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].code, '00123', 'Should be string with leading zeros');
  assertEquals(typeof result.rows[0].code, 'string', 'Should be string type');
});

test('should handle mixed type coercion in same row', () => {
  const csv = 'id,name,active,score,status\n1,John,true,95.5,pending';
  const result = parseCSV(csv);

  const row = result.rows[0];
  assertEquals(row.id, 1, 'ID should be number');
  assertEquals(row.name, 'John', 'Name should be string');
  assertEquals(row.active, true, 'Active should be boolean');
  assertEquals(row.score, 95.5, 'Score should be float');
  assertEquals(row.status, 'pending', 'Status should be string');
});

console.log('\n=== Error Handling Tests ===\n');

test('should collect errors for unclosed quotes', () => {
  const csv = 'name,value\n"John","unclosed';
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, 'Should have 1 error');
  assertEquals(result.errors[0].row, 2, 'Error should be on row 2');
  assert(
    result.errors[0].message.includes('Unclosed'),
    'Error message should mention unclosed quote'
  );
});

test('should continue parsing after error', () => {
  const csv = 'name,value\n"John","unclosed\nAlice,25';
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, 'Should have 1 error');
  assertEquals(result.rows.length, 1, 'Should have parsed 1 valid row');
  assertEquals(result.rows[0].name, 'Alice', 'Should have parsed the third line');
});

test('should collect multiple errors', () => {
  const csv = 'name,value\n"John","unclosed\n"Bob","also unclosed\nAlice,25';
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 2, 'Should have 2 errors');
  assertEquals(result.rows.length, 1, 'Should have parsed 1 valid row');
});

test('should handle rows with fewer fields than headers', () => {
  const csv = 'name,age,city\nJohn,30';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John', 'Name should match');
  assertEquals(result.rows[0].age, 30, 'Age should match');
  assertEquals(result.rows[0].city, null, 'Missing city should be null');
});

test('should handle rows with more fields than headers', () => {
  const csv = 'name,age\nJohn,30,NYC,USA';
  const result = parseCSV(csv);

  assertEquals(result.rows[0].name, 'John', 'Name should match');
  assertEquals(result.rows[0].age, 30, 'Age should match');
  assertEquals(result.rows[0].field_2, 'NYC', 'Extra field should be named field_2');
  assertEquals(result.rows[0].field_3, 'USA', 'Extra field should be named field_3');
});

console.log('\n=== Filter Tests ===\n');

test('should filter rows by predicate', () => {
  const csv = 'name,age\nJohn,30\nAlice,25\nBob,35';
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 25);
  assertEquals(filtered.rows.length, 2, 'Should have 2 rows after filter');
  assertEquals(filtered.rows[0].name, 'John', 'First row should be John');
  assertEquals(filtered.rows[1].name, 'Bob', 'Second row should be Bob');
});

test('should filter with index parameter', () => {
  const csv = 'name,value\nA,1\nB,2\nC,3';
  const result = parseCSV(csv);

  const filtered = result.filter((row, index) => index < 2);
  assertEquals(filtered.rows.length, 2, 'Should have 2 rows');
});

test('should return empty result when filter matches nothing', () => {
  const csv = 'name,age\nJohn,30\nAlice,25';
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 100);
  assertEquals(filtered.rows.length, 0, 'Should have 0 rows');
  assertEquals(filtered.headers, result.headers, 'Headers should be preserved');
});

test('should chain filters', () => {
  const csv = 'name,age,active\nJohn,30,true\nAlice,25,false\nBob,35,true';
  const result = parseCSV(csv);

  const filtered = result
    .filter((row) => row.age > 25)
    .filter((row) => row.active === true);

  assertEquals(filtered.rows.length, 1, 'Should have 1 row after chained filters');
  assertEquals(filtered.rows[0].name, 'Bob', 'Should be Bob');
});

test('should filter by string match', () => {
  const csv = 'name,city\nJohn,NYC\nAlice,LA\nBob,NYC';
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.city === 'NYC');
  assertEquals(filtered.rows.length, 2, 'Should have 2 rows from NYC');
});

console.log('\n=== Aggregation: Sum Tests ===\n');

test('should sum numeric values in a column', () => {
  const csv = 'name,value\nItem1,10\nItem2,20\nItem3,15';
  const result = parseCSV(csv);

  const total = result.sum('value');
  assertEquals(total, 45, 'Sum should be 45');
});

test('should sum with floats', () => {
  const csv = 'item,price\nA,10.5\nB,20.25\nC,5.75';
  const result = parseCSV(csv);

  const total = result.sum('price');
  assertEquals(total, 36.5, 'Sum should be 36.5');
});

test('should sum with negative numbers', () => {
  const csv = 'value\n10\n-5\n20\n-3';
  const result = parseCSV(csv);

  const total = result.sum('value');
  assertEquals(total, 22, 'Sum should be 22');
});

test('should return 0 when summing empty result', () => {
  const csv = 'value\n10\n20';
  const result = parseCSV(csv).filter(() => false);

  const total = result.sum('value');
  assertEquals(total, 0, 'Sum should be 0');
});

test('should throw error when column does not exist', () => {
  const csv = 'name,value\nItem,10';
  const result = parseCSV(csv);

  assertThrows(
    () => result.sum('nonexistent'),
    'Should throw error for nonexistent column'
  );
});

test('should ignore non-numeric values in sum', () => {
  const csv = 'item,value\nA,10\nB,text\nC,20';
  const result = parseCSV(csv);

  const total = result.sum('value');
  assertEquals(total, 30, 'Sum should be 30 (ignoring text)');
});

console.log('\n=== Aggregation: Average Tests ===\n');

test('should calculate average of numeric values', () => {
  const csv = 'value\n10\n20\n30';
  const result = parseCSV(csv);

  const avg = result.average('value');
  assertEquals(avg, 20, 'Average should be 20');
});

test('should calculate average with floats', () => {
  const csv = 'value\n10.5\n20.5\n30.0';
  const result = parseCSV(csv);

  const avg = result.average('value');
  assertEquals(avg, 20.333333333333332, 'Average should be approximately 20.33');
});

test('should return 0 for empty result', () => {
  const csv = 'value\n10';
  const result = parseCSV(csv).filter(() => false);

  const avg = result.average('value');
  assertEquals(avg, 0, 'Average should be 0');
});

test('should throw error for nonexistent column', () => {
  const csv = 'value\n10';
  const result = parseCSV(csv);

  assertThrows(
    () => result.average('nonexistent'),
    'Should throw error for nonexistent column'
  );
});

test('should average single row', () => {
  const csv = 'value\n50';
  const result = parseCSV(csv);

  const avg = result.average('value');
  assertEquals(avg, 50, 'Average of single value should be 50');
});

console.log('\n=== Aggregation: Count Tests ===\n');

test('should count total rows', () => {
  const csv = 'name\nA\nB\nC\nD';
  const result = parseCSV(csv);

  assertEquals(result.count(), 4, 'Count should be 4');
});

test('should count filtered rows', () => {
  const csv = 'name,value\nA,10\nB,20\nC,30';
  const result = parseCSV(csv).filter((row) => row.value > 15);

  assertEquals(result.count(), 2, 'Count should be 2');
});

test('should return 0 for empty result', () => {
  const csv = 'value\n10\n20';
  const result = parseCSV(csv).filter(() => false);

  assertEquals(result.count(), 0, 'Count should be 0');
});

test('should count single row', () => {
  const csv = 'name\nAlice';
  const result = parseCSV(csv);

  assertEquals(result.count(), 1, 'Count should be 1');
});

console.log('\n=== Aggregation: GroupBy Tests ===\n');

test('should group rows by column value', () => {
  const csv = 'city,name\nNYC,John\nLA,Alice\nNYC,Bob';
  const result = parseCSV(csv);

  const grouped = result.groupBy('city');
  assertEquals(grouped.size, 2, 'Should have 2 groups');
  assertEquals(grouped.get('NYC')!.length, 2, 'NYC should have 2 rows');
  assertEquals(grouped.get('LA')!.length, 1, 'LA should have 1 row');
});

test('should return Map from groupBy', () => {
  const csv = 'category,item\nA,item1\nB,item2';
  const result = parseCSV(csv);

  const grouped = result.groupBy('category');
  assert(grouped instanceof Map, 'Should return a Map');
});

test('should group by numeric column', () => {
  const csv = 'status,name\n1,Active\n0,Inactive\n1,Active2';
  const result = parseCSV(csv);

  const grouped = result.groupBy('status');
  assertEquals(grouped.size, 2, 'Should have 2 groups');
