/**
 * CSV Parser Test Suite
 * Comprehensive tests for all CSV parsing functionality
 */

import { parseCSV, CSVResult } from './csv-parser';

// Test utilities
function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`Assertion failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `Assertion failed: ${message}\nExpected: ${JSON.stringify(expected)}\nActual: ${JSON.stringify(actual)}`
    );
  }
}

function assertThrows(fn: () => void, message: string): void {
  try {
    fn();
    throw new Error(`Assertion failed: ${message} - Expected exception but none was thrown`);
  } catch (error) {
    if (error instanceof Error && error.message.includes('Assertion failed')) {
      throw error;
    }
    // Expected to throw
  }
}

function test(name: string, fn: () => void): void {
  try {
    fn();
    console.log(`вң“ ${name}`);
  } catch (error) {
    console.error(`вң— ${name}`);
    console.error(`  ${error instanceof Error ? error.message : String(error)}`);
    process.exit(1);
  }
}

