/**
 * CSV Parser Library
 * A comprehensive CSV parsing library with type coercion, error handling, and data manipulation methods
 */

interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

interface ParseError {
  row: number;
  message: string;
}

interface GroupedData {
  [key: string]: Array<Record<string, any>>;
}

class CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];

  constructor(
    rows: Array<Record<string, any>>,
    headers: string[],
    errors: ParseError[] = []
  ) {
    this.rows = rows;
    this.headers = headers;
    this.errors = errors;
  }

  /**
   * Filter rows based on a predicate function
   */
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
    const filteredRows = this.rows.filter(predicate);
    return new CSVResult(filteredRows, this.headers, this.errors);
  }

  /**
   * Sum numeric values in a column
   */
  sum(column: string): number {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    return this.rows.reduce((sum, row) => {
      const value = row[column];
      const numValue = typeof value === 'number' ? value : 0;
      return sum + numValue;
    }, 0);
  }

  /**
   * Calculate average of numeric values in a column
   */
  average(column: string): number {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    if (this.rows.length === 0) {
      return 0;
    }

    const sum = this.sum(column);
    return sum / this.rows.length;
  }

  /**
   * Count total rows
   */
  count(): number {
    return this.rows.length;
  }

  /**
   * Group rows by a column's values
   */
  groupBy(column: string): Map<string, Array<Record<string, any>>> {
    if (!this.headers.includes(column)) {
      throw new Error(`Column "${column}" does not exist`);
    }

    const grouped = new Map<string, Array<Record<string, any>>>();

    for (const row of this.rows) {
      const key = String(row[column] ?? 'null');
      if (!grouped.has(key)) {
        grouped.set(key, []);
      }
      grouped.get(key)!.push(row);
    }

    return grouped;
  }
}

/**
 * Coerce a string value to its appropriate type
 */
function coerceValue(value: string): any {
  // Handle null values
  if (value === '' || value === 'null' || value === 'NULL') {
    return null;
  }

  // Try to parse as number
  if (/^-?\d+(\.\d+)?$/.test(value)) {
    const num = parseFloat(value);
    return isNaN(num) ? value : num;
  }

  // Try to parse as boolean
  if (value.toLowerCase() === 'true') {
    return true;
  }
  if (value.toLowerCase() === 'false') {
    return false;
  }

  // Return as string
  return value;
}

/**
 * Parse a CSV string into structured data
 */
function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator ?? '\n';

  const errors: ParseError[] = [];

  if (!input || input.trim() === '') {
    return new CSVResult([], [], errors);
  }

  // Split by line separator
  const lines = input.split(lineSeparator);

  // Remove trailing empty lines
  while (lines.length > 0 && lines[lines.length - 1].trim() === '') {
    lines.pop();
  }

  if (lines.length === 0) {
    return new CSVResult([], [], errors);
  }

  let headers: string[] = [];
  const rows: Array<Record<string, any>> = [];

  for (let lineIndex = 0; lineIndex < lines.length; lineIndex++) {
    const line = lines[lineIndex];

    try {
      const fields = parseCSVLine(line, delimiter, quoteChar);

      if (lineIndex === 0) {
        // First line is headers
        headers = fields;
      } else {
        // Create object from fields
        const row: Record<string, any> = {};

        // Handle rows with fewer or more fields than headers
        for (let i = 0; i < headers.length; i++) {
          const header = headers[i];
          const field = i < fields.length ? fields[i] : '';
          row[header] = coerceValue(field);
        }

        // If there are more fields than headers, add them with generic names
        for (let i = headers.length; i < fields.length; i++) {
          const header = `field_${i}`;
          const field = fields[i];
          row[header] = coerceValue(field);
        }

        rows.push(row);
      }
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Unknown parsing error';
      errors.push({
        row: lineIndex + 1,
        message: errorMessage,
      });
    }
  }

  return new CSVResult(rows, headers, errors);
}

/**
 * Parse a single CSV line into fields
 * Handles quoted fields with escaped quotes
 */
function parseCSVLine(
  line: string,
  delimiter: string,
  quoteChar: string
): string[] {
  const fields: string[] = [];
  let currentField = '';
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];

    if (char === quoteChar) {
      // Check if it's an escaped quote (two quotes in a row)
      if (i + 1 < line.length && line[i + 1] === quoteChar) {
        // Escaped quote
        currentField += quoteChar;
        i += 2;
      } else {
        // Toggle quote state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Delimiter outside quotes
      fields.push(currentField);
      currentField = '';
      i++;
    } else {
      currentField += char;
      i++;
    }
  }

  // Add the last field
  fields.push(currentField);

  // Validate that quotes are properly closed
  if (inQuotes) {
    throw new Error('Unclosed quoted field');
  }

  return fields;
}

export { parseCSV, CSVResult, CSVOptions, ParseError };

