# CSV Parser - Real-World Examples

This document contains practical, real-world examples of using the CSV parser library.

## Example 1: Simple Data Import

**Scenario:** Import user data from CSV

```javascript
const { parseCSV } = require('./csv-parser.js');

const userCSV = `id,username,email,active,joined_date
1,john_doe,john@example.com,true,2023-01-15
2,jane_smith,jane@example.com,true,2023-02-20
3,bob_wilson,bob@example.com,false,2023-03-10`;

const result = parseCSV(userCSV);

console.log(`Loaded ${result.count()} users`);
// Loaded 3 users

result.rows.forEach(user => {
  console.log(`${user.username} (${user.email}) - Active: ${user.active}`);
});
// john_doe (john@example.com) - Active: true
// jane_smith (jane@example.com) - Active: true
// bob_wilson (bob@example.com) - Active: false
```

---

## Example 2: Financial Data Processing

**Scenario:** Analyze sales data with filtering and aggregation

```javascript
const salesCSV = `date,product,quantity,price,discount
2024-01-01,Laptop,5,1200.00,0.10
2024-01-01,Mouse,50,25.00,0.05
2024-01-02,Keyboard,30,75.00,0.15
2024-01-02,Monitor,10,350.00,0.20
2024-01-03,Laptop,3,1200.00,0.10
2024-01-03,Headphones,100,45.00,0.05`;

const result = parseCSV(salesCSV);

// Calculate total sales
const totalQuantity = result.sum('quantity');
console.log(`Total items sold: ${totalQuantity}`);
// Total items sold: 198

// Calculate average price
const avgPrice = result.average('price');
console.log(`Average item price: $${avgPrice.toFixed(2)}`);
// Average item price: $482.50

// Filter high-discount items
const discounted = result.filter(row => row.discount > 0.10);
console.log(`High-discount sales: ${discounted.count()}`);
// High-discount sales: 2

// Group by product
const byProduct = result.groupBy('product');
for (const [product, sales] of byProduct) {
  const totalQty = sales.reduce((sum, s) => sum + s.quantity, 0);
  console.log(`${product}: ${totalQty} units`);
}
// Laptop: 8 units
// Mouse: 50 units
// Keyboard: 30 units
// Monitor: 10 units
// Headphones: 100 units
```

---

## Example 3: Employee Database with Complex Filtering

**Scenario:** Analyze employee roster with multiple filters

```javascript
const employeeCSV = `employee_id,name,department,salary,hire_date,manager
1,"Smith, John",Engineering,95000,2020-01-15,true
2,"Doe, Jane",Marketing,75000,2020-06-20,false
3,"Johnson, Bob",Engineering,85000,2021-03-10,false
4,"Williams, Alice",Sales,70000,2021-09-05,true
5,"Brown, Charlie",Engineering,80000,2022-02-14,false
6,"Davis, Diana",HR,65000,2022-11-01,false
7,"Miller, Edward",Marketing,72000,2023-05-20,false
8,"Wilson, Frank",Sales,78000,2023-08-15,false`;

const result = parseCSV(employeeCSV);

// Get engineering department
const engineers = result.filter(row => row.department === 'Engineering');
console.log(`Total engineers: ${engineers.count()}`);
// Total engineers: 3

// Calculate average engineering salary
const avgEngSalary = engineers.average('salary');
console.log(`Average engineer salary: $${avgEngSalary.toFixed(2)}`);
// Average engineer salary: $86666.67

// Get managers
const managers = result.filter(row => row.manager === true);
console.log(`Total managers: ${managers.count()}`);
// Total managers: 2

// Multi-level filtering: High-paid non-managers
const highPaidStaff = result
  .filter(row => row.salary > 75000)
  .filter(row => row.manager === false);

console.log(`High-paid non-managers: ${highPaidStaff.count()}`);
highPaidStaff.rows.forEach(emp => {
  console.log(`  - ${emp.name} (${emp.department}): $${emp.salary}`);
});
// High-paid non-managers: 2
//   - Johnson, Bob (Engineering): $85000
//   - Brown, Charlie (Engineering): $80000

// Department summary
const byDept = result.groupBy('department');
for (const [dept, employees] of byDept) {
  const totalSalary = employees.reduce((sum, e) => sum + e.salary, 0);
  const avgSalary = totalSalary / employees.length;
  console.log(`${dept}: ${employees.length} employees, avg salary: $${avgSalary.toFixed(2)}`);
}
// Engineering: 3 employees, avg salary: $86666.67
// Marketing: 2 employees, avg salary: $73500.00
// Sales: 2 employees, avg salary: $74000.00
// HR: 1 employees, avg salary: $65000.00
```

