console.log(`\nGenes on forward strand: ${forward.count()}`);
// Genes on forward strand: 2
```

---

## Example 9: Error Recovery and Partial Data

**Scenario:** Handle partially corrupted CSV gracefully

```javascript
const partiallyCorruptedCSV = `id,name,email,status
1,Alice Smith,alice@example.com,active
2,"Johnson, Bob,bob@example.com,active
3,Charlie Brown,charlie@example.com,active
4,"Davis, Diana",diana@example.com,inactive
5,Eve Wilson,eve@example.com,active`;

const result = parseCSV(partiallyCorruptedCSV);

console.log(`Total records processed: ${result.count()}`);
console.log(`Parse errors: ${result.errors.length}\n`);
