```

---

## Example 10: Large Dataset Processing Pipeline

**Scenario:** ETL pipeline for processing large CSV files

```javascript
// Simulate a larger dataset
const generateLargeCSV = () => {
  const rows = ['product_id,category,quantity,cost,selling_price,profit_margin'];
  const categories = ['Electronics', 'Clothing', 'Food', 'Books', 'Toys'];

  for (let i = 1; i <= 1000; i++) {
    const category = categories[i % categories.length];
    const quantity = Math.floor(Math.random() * 1000);
    const cost = (Math.random() * 100 + 10).toFixed(2);
    const margin = (Math.random() * 0.5).toFixed(2);
    rows.push(`${i},${category},${quantity},${cost},,${margin}`);
  }

  return rows.join('\n');
};

const largeCSV = generateLargeCSV();
const result = parseCSV(largeCSV);

console.log(`Processing pipeline for ${result.count()} products\n`);

// Pipeline step 1: Filter valid products
const validProducts = result.filter(row => row.quantity > 0);
console.log(`Step 1 - Valid products: ${validProducts.count()}`);

// Pipeline step 2: High-margin products
const profitableProducts = validProducts.filter(row => row.profit_margin > 0.3);
console.log(`Step 2 - Profitable products: ${profitableProducts.count()}`);

// Pipeline step 3: Statistics
const stats = {
  totalQty: profitableProducts.sum('quantity'),
  avgQty: profitableProducts.average('quantity'),
  avgCost: profitableProducts.average('cost'),
  avgMargin: profitableProducts.average('profit_margin')
};

console.log(`\nStatistics on profitable products:`);
console.log(`  Total quantity: ${stats.totalQty}`);
console.log(`  Average quantity: ${stats.avgQty.toFixed(0)}`);
console.log(`  Average cost: $${stats.avgCost.toFixed(2)}`);
console.log(`  Average margin: ${(stats.avgMargin * 100).toFixed(1)}%`);

// Pipeline step 4: Grouping
const byCategory = profitableProducts.groupBy('category');
console.log(`\nProducts by category:`);
for (const [category, products] of byCategory) {
  console.log(`  ${category}: ${products.length} products`);
}
```

---

All examples demonstrate real-world usage patterns for the CSV parser library!

